import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from './api';
import { channels, complaintTypes, labelFrom, serviceTypes } from './constants';

const initialForm = {
  clinic_id: '',
  city: '',
  state: '',
  region: '',
  patient_name: '',
  patient_phone: '',
  channel: '',
  complaint_type: '',
  complaint_type_other: '',
  service_type: '',
  description: '',
  file: null
};

function ComplaintForm() {
  const navigate = useNavigate();
  const [clinics, setClinics] = useState([]);
  const [form, setForm] = useState(initialForm);
  const [loading, setLoading] = useState(false);
  const [feedback, setFeedback] = useState('');

  useEffect(() => {
    api.get('/clinics')
      .then((res) => setClinics(Array.isArray(res.data) ? res.data : []))
      .catch(() => setFeedback('Não foi possível carregar as clínicas.'));
  }, []);

  const activeClinics = useMemo(() => (
    clinics
      .filter((clinic) => clinic?.name && String(clinic.active ?? 1) !== '0' && !clinic.name.includes('INATIVA'))
      .sort((a, b) => a.name.localeCompare(b.name))
  ), [clinics]);

  const updateForm = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  const handleClinicChange = (event) => {
    const clinic = clinics.find((item) => String(item.id) === event.target.value);

    setForm((prev) => ({
      ...prev,
      clinic_id: clinic?.id || '',
      city: clinic?.city || '',
      state: clinic?.state || '',
      region: clinic?.region || ''
    }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setLoading(true);
    setFeedback('');

    try {
      const formData = new FormData();
      const complaintType = form.complaint_type === 'outros'
        ? form.complaint_type_other || 'Outros'
        : labelFrom(complaintTypes, form.complaint_type);
      const serviceType = labelFrom(serviceTypes, form.service_type);

      Object.entries({
        clinic_id: form.clinic_id,
        patient_name: form.patient_name,
        patient_phone: form.patient_phone,
        channel: labelFrom(channels, form.channel),
        complaint_type: complaintType,
        service_type: serviceType,
        description: form.description
      }).forEach(([key, value]) => {
        if (value) formData.append(key, value);
      });

      if (form.file) {
        formData.append('file', form.file);
      }

      await api.post('/complaints', formData);
      setFeedback('Reclamação cadastrada com sucesso.');
      setTimeout(() => navigate('/gestao'), 600);
    } catch (error) {
      setFeedback(error.response?.data?.error || 'Erro ao salvar a reclamação.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="app-page">
      <header className="page-heading">
        <div>
          <p className="eyebrow">Cadastro</p>
          <h1>Nova reclamação</h1>
          <p>Registre a demanda com dados padronizados para análise operacional e BI.</p>
        </div>

        <button className="outline-action" onClick={() => navigate('/home')}>
          Voltar para Home
        </button>
      </header>

      <form className="form-shell" onSubmit={handleSubmit}>
        <section className="form-section">
          <h2>Origem da reclamação</h2>

          <label>
            Clínica
            <select className="field" value={form.clinic_id} onChange={handleClinicChange} required>
              <option value="">Selecione a clínica</option>
              {activeClinics.map((clinic) => (
                <option key={clinic.id} value={clinic.id}>
                  {clinic.name} ({clinic.city}/{clinic.state})
                </option>
              ))}
            </select>
          </label>

          <div className="form-grid three">
            <label>
              Cidade
              <input className="field" value={form.city} placeholder="Cidade" disabled />
            </label>
            <label>
              Estado
              <input className="field" value={form.state} placeholder="Estado" disabled />
            </label>
            <label>
              Região
              <input className="field" value={form.region} placeholder="Região" disabled />
            </label>
          </div>
        </section>

        <section className="form-section">
          <h2>Dados do paciente</h2>

          <div className="form-grid two">
            <label>
              Nome do paciente
              <input
                className="field"
                value={form.patient_name}
                onChange={(event) => updateForm('patient_name', event.target.value)}
                placeholder="Nome completo"
                required
              />
            </label>

            <label>
              Telefone
              <input
                className="field"
                value={form.patient_phone}
                onChange={(event) => updateForm('patient_phone', event.target.value)}
                placeholder="(00) 00000-0000"
              />
            </label>
          </div>
        </section>

        <section className="form-section">
          <h2>Classificação</h2>

          <div className="form-grid two">
            <label>
              Canal de entrada
              <select
                className="field"
                value={form.channel}
                onChange={(event) => updateForm('channel', event.target.value)}
                required
              >
                <option value="">Selecione o canal</option>
                {channels.map((channel) => (
                  <option key={channel.value} value={channel.value}>{channel.label}</option>
                ))}
              </select>
            </label>

            <label>
              Tipo de reclamação
              <select
                className="field"
                value={form.complaint_type}
                onChange={(event) => updateForm('complaint_type', event.target.value)}
                required
              >
                <option value="">Selecione o tipo</option>
                {complaintTypes.map((type) => (
                  <option key={type.value} value={type.value}>{type.label}</option>
                ))}
              </select>
            </label>
          </div>

          {form.complaint_type === 'outros' && (
            <label>
              Descreva o outro tipo
              <input
                className="field"
                value={form.complaint_type_other}
                onChange={(event) => updateForm('complaint_type_other', event.target.value)}
                placeholder="Informe o tipo da reclamação"
                required
              />
            </label>
          )}

          <label>
            Serviço envolvido
            <select
              className="field"
              value={form.service_type}
              onChange={(event) => updateForm('service_type', event.target.value)}
              required
            >
              <option value="">Selecione o serviço</option>
              {serviceTypes.map((service) => (
                <option key={service.value} value={service.value}>{service.label}</option>
              ))}
            </select>
          </label>
        </section>

        <section className="form-section">
          <h2>Relato e evidências</h2>

          <label>
            Descrição da reclamação
            <textarea
              className="field textarea"
              value={form.description}
              onChange={(event) => updateForm('description', event.target.value)}
              placeholder="Descreva o ocorrido, expectativas do paciente e pontos de atenção."
              required
            />
          </label>

          <label>
            Anexo
            <input
              className="field"
              type="file"
              onChange={(event) => updateForm('file', event.target.files[0])}
            />
          </label>
        </section>

        {feedback && <p className="form-feedback">{feedback}</p>}

        <div className="form-actions">
          <button type="button" className="outline-action" onClick={() => navigate('/home')}>
            Cancelar
          </button>
          <button type="submit" className="primary-action" disabled={loading}>
            {loading ? 'Salvando...' : 'Salvar reclamação'}
          </button>
        </div>
      </form>
    </main>
  );
}

export default ComplaintForm;
